INSERT INTO "public"."articles" ("id", "created_at", "updated_at", "title", "content", "cover_image_url", "published_at", "status", "authored_by", "slug") VALUES ('3740e8e9-8433-4593-abcf-93cff3474cf9', '2025-09-15 15:52:05.414371+00', '2025-09-15 15:52:05.414371+00', 'Test', '{"root":{"type":"root","format":"","indent":0,"version":1,"children":[{"tag":"h1","type":"heading","format":"","indent":0,"version":1,"children":[{"mode":"normal","text":"Heading 1","type":"text","style":"","detail":0,"format":0,"version":1}],"direction":null},{"tag":"h2","type":"heading","format":"","indent":0,"version":1,"children":[{"mode":"normal","text":"Heading 2","type":"text","style":"","detail":0,"format":0,"version":1}],"direction":null},{"type":"paragraph","format":"","indent":0,"version":1,"children":[],"direction":null,"textStyle":"","textFormat":0},{"tag":"h3","type":"heading","format":"","indent":0,"version":1,"children":[{"mode":"normal","text":"Heading 3","type":"text","style":"","detail":0,"format":0,"version":1}],"direction":null},{"type":"paragraph","format":"","indent":0,"version":1,"children":[],"direction":null,"textStyle":"","textFormat":0},{"type":"paragraph","format":"","indent":0,"version":1,"children":[{"mode":"normal","text":"Bold","type":"text","style":"","detail":0,"format":1,"version":1}],"direction":null,"textStyle":"","textFormat":1},{"type":"paragraph","format":"","indent":0,"version":1,"children":[{"mode":"normal","text":"Italic","type":"text","style":"","detail":0,"format":2,"version":1}],"direction":null,"textStyle":"","textFormat":2},{"type":"paragraph","format":"","indent":0,"version":1,"children":[{"mode":"normal","text":"Underline","type":"text","style":"","detail":0,"format":8,"version":1}],"direction":null,"textStyle":"","textFormat":8},{"type":"paragraph","format":"","indent":0,"version":1,"children":[{"mode":"normal","text":"Strikethrough","type":"text","style":"","detail":0,"format":4,"version":1}],"direction":null,"textStyle":"","textFormat":4},{"type":"paragraph","format":"","indent":0,"version":1,"children":[{"mode":"normal","text":"Code","type":"text","style":"","detail":0,"format":16,"version":1}],"direction":null,"textStyle":"","textFormat":16},{"type":"quote","format":"","indent":0,"version":1,"children":[{"mode":"normal","text":"Quote","type":"text","style":"","detail":0,"format":0,"version":1}],"direction":null},{"type":"paragraph","format":"","indent":0,"version":1,"children":[],"direction":null,"textStyle":"","textFormat":0},{"alt":"Article image","src":"https://res.cloudinary.com/dbm5rzesq/image/upload/v1757951516/cesafi-articles/buxzc76fl2wwjcjuswm7.jpg","type":"image","version":1}],"direction":null}}', 'https://res.cloudinary.com/dbm5rzesq/image/upload/v1757951507/articles/cover-images/cel-banner-1757951506118.jpg', null, 'draft', 'Nicolo', 'test'), ('99211feb-96b8-48bf-991c-f10ea658d32e', '2025-09-22 08:17:19.913273+00', '2025-09-22 08:17:19.913273+00', 'TYest', '{"root":{"type":"root","format":"","indent":0,"version":1,"children":[{"type":"paragraph","format":"","indent":0,"version":1,"children":[{"mode":"normal","text":"testest","type":"text","style":"","detail":0,"format":0,"version":1}],"direction":null,"textStyle":"","textFormat":0},{"tag":"h2","type":"heading","format":"","indent":0,"version":1,"children":[{"mode":"normal","text":"Test","type":"text","style":"","detail":0,"format":0,"version":1}],"direction":null},{"tag":"h2","type":"heading","format":"","indent":0,"version":1,"children":[{"mode":"normal","text":"asdasdasdas","type":"text","style":"","detail":0,"format":0,"version":1}],"direction":null}],"direction":null}}', 'https://res.cloudinary.com/dbm5rzesq/image/upload/v1758529034/articles/cover-images/548220147-1269996615170177-8503825448933412511-n-1758529030430.jpg', '2025-09-22 08:17:55.963+00', 'published', 'Nicolo Porter', 'tyest'), ('9f99cc09-bd80-48ae-ab28-8399cb50dbeb', '2025-09-19 14:53:27.436616+00', '2025-09-19 14:53:27.436616+00', 'From Court to Console: Junemar Fajardo’s Game outside of Basketball', '{"root":{"type":"root","format":"","indent":0,"version":1,"children":[{"type":"paragraph","format":"start","indent":0,"version":1,"children":[{"mode":"normal","text":"Junemar \\"The Kraken\\" Fajardo has established himself as the most dominant force in Philippine basketball. An Asian Games Gold Medallist, Southeast Asian Games Champion, two-time Cebu Schools Athletic Foundation, Inc. (CESAFI) Most Valuable Player (MVP) and nine-time PBA All-Star, he has made himself synonymous with Philippine Basketball. If one mentions icons in Philippine Basketball, he is surely the one of the first players that come to mind.","type":"text","style":"","detail":0,"format":0,"version":1}],"direction":null,"textStyle":"","textFormat":0},{"type":"paragraph","format":"start","indent":0,"version":1,"children":[{"mode":"normal","text":"But behind the trophies and towering stature is a man who finds joy in the little things. Off the court, Junemar is frequently seen at home, not in the spotlight, but in front of a computer, quietly immersed in the world of video games.. Since his college days at the University of Cebu, he has been hooked on Dota and Call of Duty. “Ever since college pako, the same ra’g online games so until now, gaming gihapon ko, wala koy night life, so naa rakos balay pirmi,” he shared. For Junemar, gaming isn’t just something to pass the time; it’s his way of keeping life simple and enjoying a world where he feels at ease.","type":"text","style":"","detail":0,"format":0,"version":1}],"direction":null,"textStyle":"","textFormat":0},{"type":"paragraph","format":"start","indent":0,"version":1,"children":[{"mode":"normal","text":"What’s striking is how Junemar sees basketball and gaming as reflections of each other. Both, he says, demand the same things: preparation, focus, and above all, teamwork. “Dota is 5 on 5 game, so same ra sa basketball. Nag need siya ug teamwork,” he explained, drawing a clear line between the coordination he shares with his San Miguel and Gilas teammates and the strategies he uses with friends in online matches. Whether it’s preparing for a championship game or gearing up for a late-night online battle, Junemar approaches both with the same mindset: be ready, trust your team, and give your best.","type":"text","style":"","detail":0,"format":0,"version":1}],"direction":null,"textStyle":"","textFormat":0},{"type":"paragraph","format":"start","indent":0,"version":1,"children":[{"mode":"normal","text":"Just like in basketball, gaming has its own moments of pressure. Junemar admits he still feels the nerves when playing competitive matches, but the years he’s spent under the bright lights of the PBA and representing the country with Gilas Pilipinas have taught him how to stay calm, trust himself, and handle those situations better. “Bisag sa game sad ma pressure sad ka, same sad sa basketball, kung ma anad ka sa pressure dali nalang para sa imo,” he said. But even with the similarities, he’s quick to point out that nothing compares to the intensity of a championship. “Siyempre, championship game,” he smiled, reminding us that while gaming gives him comfort and fun, the thrill of basketball is still in a league of its own.","type":"text","style":"","detail":0,"format":0,"version":1}],"direction":null,"textStyle":"","textFormat":0},{"type":"paragraph","format":"start","indent":0,"version":1,"children":[{"mode":"normal","text":"Beyond his personal life, Junemar understands how gaming has become part of the younger generation’s culture. When asked about CESAFI launching its own Esports League (CEL), his eyes lit up. “Maayo, maayo kay karon man gud most of the young generations kay mga gamers na so maayo na ron,” he said, expressing genuine support for the movement. It’s a reminder that “The Kraken” isn’t just a giant on the court but also someone who understands and connects with the passions of today’s youth. In the end, Junemar Fajardo’s greatness is not only measured by the trophies he has lifted, but by the way he stays grounded in who he is. On the court, he is “The Kraken,” an unstoppable force. Off it, he is a reminder that true champions are those who embrace balance, stay connected to their passions, and never lose sight of the simple joys that make life meaningful.","type":"text","style":"","detail":0,"format":0,"version":1}],"direction":null,"textStyle":"","textFormat":0}],"direction":null}}', 'https://res.cloudinary.com/dbm5rzesq/image/upload/v1758293600/articles/cover-images/549994427-783560794308630-1799472713823797397-n-1758293596465.jpg', '2025-09-21 12:25:30.253+00', 'published', 'Mheirady Ashley Espinoza and Dan Ballares', 'from-court-to-console-junemar-fajardos-game-outside-of-basketball'), ('c57df3eb-190d-47b7-9b10-830312a57790', '2025-09-15 10:18:43.138106+00', '2025-09-15 10:18:43.138106+00', 'September ''25', '{"root":{"type":"root","format":"","indent":0,"version":1,"children":[{"type":"paragraph","format":"","indent":0,"version":1,"children":[{"mode":"normal","text":"September 15, 2025 – CESAFI has officially kicked off its silver anniversary season, Season 25, with a series of grand events and exhilarating games that have Cebuanos buzzing.","type":"text","style":"","detail":0,"format":0,"version":1},{"mode":"normal","text":"1","type":"text","style":"","detail":0,"format":64,"version":1},{"mode":"normal","text":" The festivities began with a fun run and a star-studded Hall of Fame ceremony, leading up to the much-anticipated opening games at the newly renovated Cebu Coliseum.","type":"text","style":"","detail":0,"format":0,"version":1}],"direction":null,"textStyle":"","textFormat":0},{"type":"paragraph","format":"","indent":0,"version":1,"children":[],"direction":null,"textStyle":"","textFormat":0},{"type":"paragraph","format":"","indent":0,"version":1,"children":[],"direction":null,"textStyle":"","textFormat":0},{"tag":"h2","type":"heading","format":"","indent":0,"version":1,"children":[{"mode":"normal","text":"Basketball Action Heats Up the Coliseum 🏀","type":"text","style":"","detail":0,"format":0,"version":1}],"direction":null},{"type":"paragraph","format":"","indent":0,"version":1,"children":[],"direction":null,"textStyle":"","textFormat":0},{"type":"paragraph","format":"","indent":0,"version":1,"children":[{"mode":"normal","text":"The centerpiece of CESAFI, the basketball tournament, started with a bang this weekend, featuring several thrilling matchups.","type":"text","style":"","detail":0,"format":0,"version":1},{"mode":"normal","text":"2","type":"text","style":"","detail":0,"format":64,"version":1}],"direction":null,"textStyle":"","textFormat":0},{"type":"paragraph","format":"","indent":0,"version":1,"children":[],"direction":null,"textStyle":"","textFormat":0},{"type":"paragraph","format":"","indent":0,"version":1,"children":[],"direction":null,"textStyle":"","textFormat":0},{"tag":"h3","type":"heading","format":"","indent":0,"version":1,"children":[{"mode":"normal","text":"Collegiate Division: Cheetahs Stun Jaguars","type":"text","style":"","detail":0,"format":0,"version":1}],"direction":null},{"type":"paragraph","format":"","indent":0,"version":1,"children":[],"direction":null,"textStyle":"","textFormat":0},{"type":"paragraph","format":"","indent":0,"version":1,"children":[{"mode":"normal","text":"Benedicto College (BC) Cheetahs pulled off a major upset against the University of San Jose-Recoletos (USJ-R) Jaguars, winning 76-74 in a down-to-the-wire game.","type":"text","style":"","detail":0,"format":0,"version":1},{"mode":"normal","text":"3","type":"text","style":"","detail":0,"format":64,"version":1},{"mode":"normal","text":" BC''s ","type":"text","style":"","detail":0,"format":0,"version":1},{"mode":"normal","text":"Serge Gabines","type":"text","style":"","detail":0,"format":1,"version":1},{"mode":"normal","text":" was the hero of the night, sealing the comeback victory with a gutsy three-point play in the final seconds.","type":"text","style":"","detail":0,"format":0,"version":1},{"mode":"normal","text":"4","type":"text","style":"","detail":0,"format":64,"version":1}],"direction":null,"textStyle":"","textFormat":0},{"type":"paragraph","format":"","indent":0,"version":1,"children":[],"direction":null,"textStyle":"","textFormat":0},{"type":"paragraph","format":"","indent":0,"version":1,"children":[{"type":"horizontalrule","version":1}],"direction":null,"textStyle":"","textFormat":0},{"type":"paragraph","format":"","indent":0,"version":1,"children":[],"direction":null,"textStyle":"","textFormat":0},{"tag":"h3","type":"heading","format":"","indent":0,"version":1,"children":[{"mode":"normal","text":"High School Division: Baby Jaguars Win a Thriller","type":"text","style":"","detail":0,"format":0,"version":1}],"direction":null},{"type":"paragraph","format":"","indent":0,"version":1,"children":[],"direction":null,"textStyle":"","textFormat":0},{"type":"paragraph","format":"","indent":0,"version":1,"children":[{"mode":"normal","text":"In the high school opener, the USJ-R Baby Jaguars shocked the favored Cebu Eastern College (CEC) Dragons with a 70-62 overtime victory.","type":"text","style":"","detail":0,"format":0,"version":1},{"mode":"normal","text":"5","type":"text","style":"","detail":0,"format":64,"version":1},{"mode":"normal","text":" The game-changer came with just six seconds left in regulation when USJ-R''s team captain, ","type":"text","style":"","detail":0,"format":0,"version":1},{"mode":"normal","text":"Clyve Heinrich Antig","type":"text","style":"","detail":0,"format":1,"version":1},{"mode":"normal","text":", was fouled while shooting a three-pointer.","type":"text","style":"","detail":0,"format":0,"version":1},{"mode":"normal","text":"6","type":"text","style":"","detail":0,"format":64,"version":1},{"mode":"normal","text":" He sank all three free throws to tie the game and force overtime, where the Baby Jaguars dominated.","type":"text","style":"","detail":0,"format":0,"version":1},{"mode":"normal","text":"7","type":"text","style":"","detail":0,"format":64,"version":1}],"direction":null,"textStyle":"","textFormat":0},{"type":"paragraph","format":"","indent":0,"version":1,"children":[],"direction":null,"textStyle":"","textFormat":0},{"type":"paragraph","format":"","indent":0,"version":1,"children":[{"mode":"normal","text":"In the other high school game, the Don Bosco Technical College (DBTC) Greywolves secured a 67-62 victory over the San Carlos School of Cebu Baby Warriors.","type":"text","style":"","detail":0,"format":0,"version":1},{"mode":"normal","text":"8","type":"text","style":"","detail":0,"format":64,"version":1}],"direction":null,"textStyle":"","textFormat":0},{"type":"paragraph","format":"","indent":0,"version":1,"children":[],"direction":null,"textStyle":"","textFormat":0},{"type":"paragraph","format":"","indent":0,"version":1,"children":[{"type":"horizontalrule","version":1}],"direction":null,"textStyle":"","textFormat":0},{"type":"paragraph","format":"","indent":0,"version":1,"children":[],"direction":null,"textStyle":"","textFormat":0},{"tag":"h2","type":"heading","format":"","indent":0,"version":1,"children":[{"mode":"normal","text":"A Season of Celebration and Recognition","type":"text","style":"","detail":0,"format":0,"version":1}],"direction":null},{"type":"paragraph","format":"","indent":0,"version":1,"children":[],"direction":null,"textStyle":"","textFormat":0},{"type":"paragraph","format":"","indent":0,"version":1,"children":[{"mode":"normal","text":"The 25th CESAFI season, themed \\"25 Years of Excellence: Honoring the Past, Embracing the Future,\\" is a celebration of the league''s rich history.","type":"text","style":"","detail":0,"format":0,"version":1},{"mode":"normal","text":"9","type":"text","style":"","detail":0,"format":64,"version":1},{"mode":"normal","text":" It kicked off with an anniversary fun run and a spectacular opening ceremony.","type":"text","style":"","detail":0,"format":0,"version":1}],"direction":null,"textStyle":"","textFormat":0},{"type":"paragraph","format":"","indent":0,"version":1,"children":[],"direction":null,"textStyle":"","textFormat":0},{"type":"paragraph","format":"","indent":0,"version":1,"children":[{"mode":"normal","text":"A major highlight was the inaugural ","type":"text","style":"","detail":0,"format":0,"version":1},{"mode":"normal","text":"CESAFI Hall of Fame Awards","type":"text","style":"","detail":0,"format":1,"version":1},{"mode":"normal","text":", where some of the league''s most distinguished alumni were honored.","type":"text","style":"","detail":0,"format":0,"version":1},{"mode":"normal","text":"10","type":"text","style":"","detail":0,"format":64,"version":1},{"mode":"normal","text":" The first batch of inductees included PBA superstar and Cebu native ","type":"text","style":"","detail":0,"format":0,"version":1},{"mode":"normal","text":"June Mar Fajardo","type":"text","style":"","detail":0,"format":1,"version":1},{"mode":"normal","text":", who expressed deep gratitude to CESAFI for being the starting point of his illustrious career.","type":"text","style":"","detail":0,"format":0,"version":1},{"mode":"normal","text":"11","type":"text","style":"","detail":0,"format":64,"version":1}],"direction":null,"textStyle":"","textFormat":0},{"type":"paragraph","format":"","indent":0,"version":1,"children":[],"direction":null,"textStyle":"","textFormat":0},{"type":"paragraph","format":"","indent":0,"version":1,"children":[{"mode":"normal","text":"The opening also featured the Miss CESAFI 2025 pageant.","type":"text","style":"","detail":0,"format":0,"version":1},{"mode":"normal","text":"12","type":"text","style":"","detail":0,"format":64,"version":1},{"mode":"normal","text":" ","type":"text","style":"","detail":0,"format":0,"version":1},{"mode":"normal","text":"Stefanie Przewodnik","type":"text","style":"","detail":0,"format":1,"version":1},{"mode":"normal","text":" of the University of San Carlos (USC) was crowned in the college division, while ","type":"text","style":"","detail":0,"format":0,"version":1},{"mode":"normal","text":"Pavitar Kaur","type":"text","style":"","detail":0,"format":1,"version":1},{"mode":"normal","text":" of Cebu Doctors'' University (CDU) won the high school title.","type":"text","style":"","detail":0,"format":0,"version":1},{"mode":"normal","text":"13","type":"text","style":"","detail":0,"format":64,"version":1}],"direction":null,"textStyle":"","textFormat":0},{"type":"paragraph","format":"","indent":0,"version":1,"children":[],"direction":null,"textStyle":"","textFormat":0}],"direction":null}}', 'https://res.cloudinary.com/dbm5rzesq/image/upload/v1757931507/articles/cover-images/image-removebg-preview--8--1757931505367.png', null, 'draft', 'Bee', 'september-25'), ('e9a4b95d-8c3c-493e-aac9-5613e5f9e096', '2025-09-21 12:29:12.622287+00', '2025-09-21 12:29:12.622287+00', 'UCLM, UV DISPATCH FOES IN RESPECTIVE SEASON OPENERS', '{"root":{"type":"root","format":"","indent":0,"version":1,"children":[{"type":"paragraph","format":"start","indent":0,"version":1,"children":[{"mode":"normal","text":"CESAFI Thursday action featured the University of Cebu Lapu-Lapu and Mandaue (UCLM) Junior Webmasters as they reigned supreme against the University of San Jose-Recoletos (USJ-R) Jaguar Cubs, 63-53, in the High School Division; while the defending champions University of the Visayas (UV) Green Lancers are on a sizzling start after squeaking past the University of Southern Philippines Foundation (USPF) Panthers, 74-70, in the College Division.","type":"text","style":"","detail":0,"format":0,"version":1}],"direction":null,"textStyle":"","textFormat":0},{"type":"paragraph","format":"start","indent":0,"version":1,"children":[{"mode":"normal","text":"In the juniors’ game, both Junior Webmasters and Jaguar Cubs showed relentless defense in their ends of the court as both teams found it hard to convert easy baskets into points as they headed into halftime with a deadlock, 27-27.","type":"text","style":"","detail":0,"format":0,"version":1}],"direction":null,"textStyle":"","textFormat":0},{"type":"paragraph","format":"start","indent":0,"version":1,"children":[{"mode":"normal","text":"The game shifted after the dugout as UCLM went berserk in the later portion of the 3rd quarter to command a 46-39 lead heading to the final frame.","type":"text","style":"","detail":0,"format":0,"version":1}],"direction":null,"textStyle":"","textFormat":0},{"type":"paragraph","format":"start","indent":0,"version":1,"children":[{"mode":"normal","text":"Since then, the Junior Webmasters never looked back as their lead ballooned to as much as 15, 56-41 in the fourth quarter and ultimately seal the deal and their first win, 63-53.","type":"text","style":"","detail":0,"format":0,"version":1}],"direction":null,"textStyle":"","textFormat":0},{"type":"paragraph","format":"start","indent":0,"version":1,"children":[{"mode":"normal","text":"Wade Luche posted a 12-12 double-double to lead the Junior Webmasters. Rafael Calo added 10 points, four rebounds, and four steals.","type":"text","style":"","detail":0,"format":0,"version":1}],"direction":null,"textStyle":"","textFormat":0},{"type":"paragraph","format":"start","indent":0,"version":1,"children":[{"mode":"normal","text":"Moving on to the Seniors’ edition, reigning champs UV opened their title defense with a hard-earned 74-70 win against the revamped USPF team who fought their way back late in the fourth, but the Green Lancers showed their championship pedigree as they held off in the dying seconds of the fourth.","type":"text","style":"","detail":0,"format":0,"version":1}],"direction":null,"textStyle":"","textFormat":0},{"type":"paragraph","format":"start","indent":0,"version":1,"children":[{"mode":"normal","text":"The Gary Cortes lead UV held control for the majority of the match showcasing their unselfish basketball system as they did not let the Panthers attain the game, with them leading 73-71 late in the fourth.","type":"text","style":"","detail":0,"format":0,"version":1}],"direction":null,"textStyle":"","textFormat":0},{"type":"paragraph","format":"start","indent":0,"version":1,"children":[{"mode":"normal","text":"A USPF resurgence in the dying minutes sparked 9 unanswered points for the Panthers as they managed to trim down the lead to three, 70-73.","type":"text","style":"","detail":0,"format":0,"version":1}],"direction":null,"textStyle":"","textFormat":0},{"type":"paragraph","format":"start","indent":0,"version":1,"children":[{"mode":"normal","text":"The Green Lancers remained composed despite the persistent trap defense, but Kent Ivo Salarda sank a game-sealing free throw to put the game out of hand, 74-70.","type":"text","style":"","detail":0,"format":0,"version":1}],"direction":null,"textStyle":"","textFormat":0},{"type":"paragraph","format":"start","indent":0,"version":1,"children":[{"mode":"normal","text":"Ivan Clark Arsola powered UV with his 13 points, six rebounds, and two assists. Albert John Sacayan also chipped in 12 points.","type":"text","style":"","detail":0,"format":0,"version":1}],"direction":null,"textStyle":"","textFormat":0}],"direction":null}}', 'https://res.cloudinary.com/dbm5rzesq/image/upload/v1758457740/articles/cover-images/549789041-1272057651630740-5037540793446227562-n-1758457731981.jpg', '2025-09-21 12:28:29.171+00', 'published', 'Drexler Alib', 'uclm-uv-dispatch-foes-in-respective-season-openers'), ('f3696330-6a81-4263-9a5b-c3988bc46dbc', '2025-09-21 12:39:17.432726+00', '2025-09-21 12:39:17.432726+00', 'UV, UC SECURE FIRST WIN', '{"root":{"type":"root","format":"","indent":0,"version":1,"children":[{"type":"paragraph","format":"start","indent":0,"version":1,"children":[{"mode":"normal","text":"More schools are making their presence felt in the ","type":"text","style":"","detail":0,"format":0,"version":1},{"rel":null,"url":"https://www.facebook.com/hashtag/cesafi?__eep__=6&__cft__[0]=AZUOAeSMsOtAqSBsBTiNPJlZJmveKKHaRdMp0BvCeLDiBwbFJumPPv2NnvNyH83qvyvGss_ggO4y_Xazmrtdtg3tWIDib53hIZz0EdOkpsKvDGnlMj1YcSoeHGM3hGebJccdPu1UTl9mAqGcVECgGrJB78X01zJ9uEzdGN4Gu9DT-JRG7Q5spsj45KsPrvhA1U0&__tn__=*NK-R","type":"link","title":null,"format":"","indent":0,"target":null,"version":1,"children":[{"mode":"normal","text":"#CESAFI","type":"text","style":"","detail":0,"format":0,"version":1}],"direction":null},{"mode":"normal","text":" Season 25 basketball campaigns. In the high school division, the University of the Visayas (UV) Baby Lancers squared off with the Benedicto College (BC) Baby Cheetahs. On the collegiate side, the Cebu Institute of Technology–University (CIT-U) Wildcats faced the University of Cebu (UC) Webmasters.","type":"text","style":"","detail":0,"format":0,"version":1}],"direction":null,"textStyle":"","textFormat":0},{"type":"paragraph","format":"start","indent":0,"version":1,"children":[{"mode":"normal","text":"The high school match between the Baby Lancers and the Baby Cheetahs was fast-paced, driven by UV’s aggressive plays that reflected the preparation they had put in for the season. By halftime, it was still a close contest, with the Baby Lancers holding a slim 5-point lead.","type":"text","style":"","detail":0,"format":0,"version":1}],"direction":null,"textStyle":"","textFormat":0},{"type":"paragraph","format":"start","indent":0,"version":1,"children":[{"mode":"normal","text":"Alexander Jose Ejurango contributed 7 points for UV, while BC’s Lance Andrei Villarin kept his team within reach with 8 points. But the tight battle didn’t last long, as the Baby Lancers’ rookie-studded lineup turned up the intensity, pulling away and securing a commanding 76-48 victory over the Baby Cheetahs.","type":"text","style":"","detail":0,"format":0,"version":1},{"type":"linebreak","version":1}],"direction":null,"textStyle":"","textFormat":0},{"alt":"Article image","src":"https://res.cloudinary.com/dbm5rzesq/image/upload/v1758458353/cesafi-articles/own6a2696atg5knjgdz4.jpg","type":"image","version":1},{"type":"paragraph","format":"start","indent":0,"version":1,"children":[],"direction":null,"textStyle":"","textFormat":0},{"type":"paragraph","format":"start","indent":0,"version":1,"children":[{"mode":"normal","text":"Rookie standout Alexander Jose Ejurango spearheaded the dominance with a double-double of 13 points and 13 rebounds. After the game, Ejurango credited their win to the team’s defensive focus. He added that consistency has been a key to their early success, promising that the same effort and discipline will carry over into their upcoming matches.","type":"text","style":"","detail":0,"format":0,"version":1}],"direction":null,"textStyle":"","textFormat":0},{"type":"paragraph","format":"start","indent":0,"version":1,"children":[{"mode":"normal","text":"Benedicto College will look to bounce back when they take on the Don Bosco Technical College Greywolves on Sunday, September 21, at 12:30 p.m., while UV is set to clash with San Carlos School of Cebu on Saturday, also at 12:30 p.m.","type":"text","style":"","detail":0,"format":0,"version":1}],"direction":null,"textStyle":"","textFormat":0},{"type":"paragraph","format":"start","indent":0,"version":1,"children":[{"mode":"normal","text":"The collegiate match kicked off with intensity, as players from the CIT-U Wildcats and UC Webmasters were both eager to set the tone for their CESAFI opener. It wasn’t an easy victory for the Webmasters, as the Wildcats clawed their way back, showing the improvements they’ve made this season.","type":"text","style":"","detail":0,"format":0,"version":1}],"direction":null,"textStyle":"","textFormat":0},{"type":"paragraph","format":"start","indent":0,"version":1,"children":[{"mode":"normal","text":"CIT-U struck first, but the Webmasters refused to give up the lead, holding a narrow advantage of 22-21. The Wildcats’ relentless energy kept the game intense and physical, closing the gap to just a two-point deficit at 38-36.","type":"text","style":"","detail":0,"format":0,"version":1}],"direction":null,"textStyle":"","textFormat":0},{"type":"paragraph","format":"start","indent":0,"version":1,"children":[{"mode":"normal","text":"Ultimately, the Webmasters sealed the game with a 74-63 win, with Ricofer Sordilla shining as Player of the Game after contributing 17 points, two assists, and five steals.","type":"text","style":"","detail":0,"format":0,"version":1}],"direction":null,"textStyle":"","textFormat":0},{"type":"paragraph","format":"start","indent":0,"version":1,"children":[{"mode":"normal","text":"Sordilla emphasized that he prepared thoroughly for the opener, focusing on his role as shooting guard and aligning with the team’s goal of winning their first match of the season. However, he also acknowledged that their defense still needs work, as the Wildcats were able to find scoring opportunities despite the Webmasters’ strong offense.","type":"text","style":"","detail":0,"format":0,"version":1}],"direction":null,"textStyle":"","textFormat":0},{"type":"paragraph","format":"start","indent":0,"version":1,"children":[{"mode":"normal","text":"Can the UC Webmasters maintain their winning streak? Watch out this Saturday, September 20, as they face the University of San Carlos (USC) Warriors at 3:30 p.m. Meanwhile, the CIT-U Wildcats will look to redeem themselves on Sunday, September 21, at 5 p.m. against the Benedicto College (BC) Cheetahs.","type":"text","style":"","detail":0,"format":0,"version":1}],"direction":null,"textStyle":"","textFormat":0}],"direction":null}}', 'https://res.cloudinary.com/dbm5rzesq/image/upload/v1758458342/articles/cover-images/548220147-1269996615170177-8503825448933412511-n-1758458333199.jpg', null, 'cancelled', 'Nicolo Porter', 'uv-uc-secure-first-win');